import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import MenuLateral from '../components/MenuLateral';

const statusCores = {
  NOVO: '#1976d2',
  ATIVO: '#388e3c',
  CORRIGIR: '#fbc02d',
  SUSPENSO: '#d32f2f'
};
const statusNomes = {
  NOVO: 'Novo',
  ATIVO: 'Ativo',
  CORRIGIR: 'Corrigir',
  SUSPENSO: 'Suspenso'
};

const EditarPerfil = () => {
  const { id } = useParams();
  const [cliente, setCliente] = useState(null);
  const [loading, setLoading] = useState(true);
  const [erro, setErro] = useState(null);
  const [form, setForm] = useState({ razaoSocial: '', cnpj: '', email: '', telefone: '', consultoria: '' });

  useEffect(() => {
    setLoading(true);
    setErro(null);
    fetch(`http://localhost:5000/api/clientes/${id}`)
      .then(async resp => {
        let data = null;
        try {
          data = await resp.json();
        } catch (e) {}
        if (!resp.ok) {
          setErro('Cliente não encontrado.');
          setCliente(null);
          setLoading(false);
          return;
        }
        setCliente(data);
        setForm({
          razaoSocial: data.razaoSocial,
          cnpj: data.cnpj,
          email: data.email,
          telefone: data.telefone,
          consultoria: data.consultoria
        });
        setLoading(false);
      })
      .catch(() => {
        setErro('Erro ao buscar cliente.');
        setLoading(false);
      });
  }, [id]);

  const handleChange = e => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const handleSalvar = async e => {
    e.preventDefault();
    const resp = await fetch(`http://localhost:5000/api/clientes/${id}`, {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(form)
    });
    if (resp.ok) {
      // Atualiza cliente após edição
      const data = await resp.json();
      setCliente(data);
      alert('Perfil atualizado com sucesso!');
    }
  };

  if (loading) return <p>Carregando detalhes...</p>;
  if (erro) return <p style={{color:'red'}}>{erro}</p>;
  if (!cliente) return null;

  return (
    <div style={{display:'flex'}}>
      <MenuLateral
        voltarLink={<Link to="/" style={{textDecoration:'none',color:'#1976d2',fontWeight:'bold',fontSize:'1.1rem',display:'block',marginBottom:'1.5rem',marginTop:'1rem'}}>&larr; Voltar</Link>}
        clienteInfo={
          <div style={{marginBottom: 16, textAlign: 'center'}}>
            <div style={{fontWeight:700, fontSize: '1.1rem', color: '#fff'}}>{cliente.razaoSocial}</div>
            <div style={{fontWeight:500, fontSize: '0.95rem', color: '#fff'}}>CNPJ: {cliente.cnpj}</div>
          </div>
        }
      />
      <div style={{maxWidth:'1100px',margin:'2rem auto',marginLeft:200,flex:1}}>
        {/* Painel centralizado com informações do cliente */}
        <div style={{
          background:'#fff',
          borderRadius:'16px',
          minHeight:'220px',
          boxShadow:'0 2px 8px #0001',
          padding:'2.5rem 2rem 2rem 2rem',
          margin:'2rem auto',
          maxWidth:600,
          display:'flex',
          flexDirection:'column',
          alignItems:'center',
          justifyContent:'center',
        }}>
          <div style={{fontSize:'1.2rem',color:'#1976d2',fontWeight:700,marginBottom:8}}>Painel Cliente</div>
          <div style={{fontSize:'1.1rem',fontWeight:600,marginBottom:2}}>Razão Social</div>
          <input name="razaoSocial" value={form.razaoSocial} onChange={handleChange} style={{fontSize:'1.25rem',fontWeight:700,marginBottom:8, textAlign:'center', width:'100%'}} />
          <div style={{display:'flex',gap:'2.5rem',marginBottom:8}}>
            <div style={{fontSize:'1.05rem'}}><b>CNPJ</b><br/>
              <input name="cnpj" value={form.cnpj} onChange={handleChange} style={{textAlign:'center', width:'100%'}} />
            </div>
            <div style={{fontSize:'1.05rem'}}><b>Status</b><br/><span style={{background:statusCores[cliente.status],color:'#fff',borderRadius:'12px',padding:'0.2rem 1rem',fontWeight:600,fontSize:'0.95rem'}}>{statusNomes[cliente.status]}</span></div>
          </div>
          <div style={{fontSize:'1.05rem',marginBottom:4}}><b>E-mail:</b> <input name="email" value={form.email} onChange={handleChange} style={{textAlign:'center', width:'100%'}} /></div>
          <div style={{fontSize:'1.05rem',marginBottom:4}}><b>Telefone:</b> <input name="telefone" value={form.telefone} onChange={handleChange} style={{textAlign:'center', width:'100%'}} /></div>
          <div style={{fontSize:'1.05rem',marginBottom:4}}><b>Consultoria:</b> <input name="consultoria" value={form.consultoria} onChange={handleChange} style={{textAlign:'center', width:'100%'}} /></div>
                    {/* Novos campos personalizados para GERENCIADOR */}
                    <div style={{fontSize:'1.05rem',marginBottom:4}}>
                      <b>Campo 1:</b> <input name="campo1" value={form.campo1 || ''} onChange={handleChange} style={{textAlign:'center', width:'100%'}} />
                    </div>
                    <div style={{fontSize:'1.05rem',marginBottom:4}}>
                      <b>Campo 2:</b> <input name="campo2" value={form.campo2 || ''} onChange={handleChange} style={{textAlign:'center', width:'100%'}} />
                    </div>
                    <div style={{fontSize:'1.05rem',marginBottom:12}}>
                      <b>Campo 3:</b> <input name="campo3" value={form.campo3 || ''} onChange={handleChange} style={{textAlign:'center', width:'100%'}} />
                    </div>
          <form onSubmit={handleSalvar} style={{marginTop:16, width:'100%', display:'flex', justifyContent:'center'}}>
            <button type="submit" style={{background:'#1976d2',color:'#fff',border:'2px solid #1976d2',borderRadius:'6px',padding:'0.5rem 2rem',fontWeight:'bold',fontSize:'1rem',cursor:'pointer',transition:'background 0.2s'}}>Salvar</button>
          </form>
        </div>
      </div>
    </div>
  );
};

export default EditarPerfil;
